/*eslint-disable*/import type{Messages}from"@lingui/core";export const messages=JSON.parse("{\"++OGw8\":[\"H.264 (also called AVC) is the most widely supported video codec in existence: every browser, phone, set-top box, and hardware decoder of the last 15+ years plays it. It is the safe default for compatibility. Note that software H.264/H.265 encoders carry a GPL license obligation in Multiview's build, so the default (license-clean) image encodes them only with a hardware encoder; choosing a software H.264 encode means using the GPL image variant.\"],\"+1ISis\":[\"Idempotency\"],\"+33GcK\":[\"PTP (Precision Time Protocol)\"],\"+3HeXG\":[\"Cleared only\"],\"+4Md63\":[\"Accessible toasts announce via a live region.\"],\"+80OOq\":[\"Names declared by the audio routing block; the program bus is always available as \\\"prog\\\".\"],\"+Cyh5T\":[\"Delete profile\"],\"+J3Ub3\":[\"Theme: system. Switch to light.\"],\"+PEqRB\":[\"Configured overlay layers.\"],\"+azfQ4\":[\"The tile lifecycle\"],\"+hNGcs\":[\"UMD (Under-Monitor Display)\"],\"+jsLS0\":[\"Add at least one cell to the layout.\"],\"+lTHTl\":[\"This permanently removes the layout. Running outputs are not affected until a new layout is applied.\"],\"+ztzfF\":[\"Source URL\"],\"/53Ld5\":[\"AMD\"],\"/E2h56\":[\"Delete salvo\"],\"/I7pfw\":[\"Glitchy, corrupt, and malformed inputs are the expected workload, not an edge case: decode errors on one stream are tolerated and recovered per tile, and a broken track inside a transport (for example a damaged subtitle rendition) is warned about and recovered without killing the streams alongside it.\"],\"/IX/7x\":[\"Other\"],\"/Pp3Dl\":[\"The immutable change log: who changed what, and when, on the engine media timeline. Read-only.\"],\"/YadRY\":[\"Background fill as a hex color (e.g. #101014).\"],\"/dUkgN\":[\"Start, stop, and swap actions accept an <0>Idempotency-Key</0> so a retried request is applied at most once.\"],\"/gaSVU\":[\"Roadmap\"],\"/j2EVp\":[[\"0\"],\" documentation results\"],\"/jUK37\":[\"Centre y (px)\"],\"/rTz0M\":[\"Audio\"],\"/ruXTL\":[\"Optimistic concurrency\"],\"/rvyEL\":[\"Color range\"],\"/w2ens\":[\"Frame rate must be an exact rational like 30000/1001 — not a decimal.\"],\"0+gcp/\":[\"Could not load sources:\"],\"0Sf5tf\":[\"Could not delete salvo\"],\"0Sv/fy\":[\"Multiview tone-maps HDR tiles into an SDR canvas (anchored so normal \\\"reference white\\\" content stays at a sensible brightness rather than scaling everything down), and only treats a stream as HDR when it is explicitly tagged as such — resolution alone never implies HDR. The canvas itself can also be configured as HDR (PQ or HLG) for monitoring HDR productions.\"],\"0WXnrk\":[\"Multiview itself never trades the output cadence away: under load it degrades the cheapest tiles first and keeps the program output's timing intact.\"],\"0hZvzy\":[\"Actions that take time return <0>202 Accepted</0> with an operation id; the final result arrives on the realtime stream, not in the HTTP response body.\"],\"0jgJ00\":[\"Network delivery where one sender transmits a single copy of a stream to a group address and the network fans it out to every subscribed receiver. Extremely efficient for in-facility distribution, but requires a managed network that routes multicast. Receivers subscribe via MLDv2 (IPv6) or IGMP (legacy IPv4).\"],\"0qd1Ok\":[\"Waiting for a frame…\"],\"0tGbfN\":[\"Delete tally profile?\"],\"0zaXWu\":[\"Encoder\"],\"108F2g\":[\"Primaries\"],\"1JioTh\":[\"Width (px)\"],\"1ba70W\":[\"Stale\"],\"1dhpFr\":[\"No results.\"],\"1gZQhL\":[\"Monitoring\"],\"1kD043\":[\"Remote contribution feeds\"],\"1mssPu\":[\"Multiview composites the canvas <0>once</0> per tick, encodes it <1>once per rendition</1>, and fans the same encoded packets out to every output that wants that rendition. Serving the wall over HLS, RTSP, and an SRT push at the same codec, resolution, and bitrate costs one encode — not three. A second encode is created only when an output genuinely needs a different codec, resolution, or bitrate.\"],\"1sQbQP\":[\"GPU vendor\"],\"1v4jCG\":[\"Magazine-addressed page, 100–899.\"],\"1vpB09\":[\"Styling: <0>z</0> stacking order, <1>opacity</1>, <2>corner_radius</2>, and a <3>border</3>.\"],\"1wEIqr\":[\"Ours of host total\"],\"27tEkD\":[\"TCP only; stalls then reconnects\"],\"2C4bN/\":[\"Embedded CEA-608/708\"],\"2Gk99R\":[\"You can also run the binary directly against a config file with <0>multiview run path/to/multiview.toml</0>. See the sections below for the container, compose, config, and API details.\"],\"2LdpC4\":[\"Spend buffer where the network is bad (the internet leg), not where it is good (the facility LAN).\"],\"2cjkV2\":[\"Clauses\"],\"2h1oP1\":[\"Enter an API key.\"],\"2p/pgE\":[\"A source is an ingest input bound into the multiview by id.\"],\"32FNIs\":[\"Index→cell rules\"],\"3DYE4p\":[\"Optional <0>captions</0> select a caption or subtitle track (auto, teletext page, CEA-608/708 service, a track id, or a sidecar file). The engine never decodes a track it will not show.\"],\"3VoYe7\":[\"The services in the quick-start compose file and how to bring them up and down.\"],\"3daTgl\":[\"Blank renders UTC.\"],\"3e0biw\":[\"Add to layout\"],\"3geqwP\":[\"Automatic (default)\"],\"3qwjra\":[\"Compose reference\"],\"3rdEtu\":[\"Destination URL\"],\"3tPTJU\":[\"Frame-accurate facilities use PTP because it is the only way to make many independent devices agree on \\\"now\\\" tightly enough to cut between them mid-frame. Two cameras of the same event locked to the same grandmaster produce frames that genuinely correspond in time — something no amount of buffering can recreate after the fact.\"],\"42Z9wy\":[\"Stacking\"],\"45MZFs\":[\"Commands\"],\"4BVSqC\":[\"Choose light, dark, or follow the system.\"],\"4Cr1FG\":[\"The document is validated as a whole: source and cell ids must be unique, every <0>input_id</0> must resolve to a declared source, every grid cell must reference an existing area, and the cadence must be a usable rational. Because TOML and JSON encode the same model, a config can be authored by hand and exported as JSON over the API, or vice versa.\"],\"4UZxp9\":[\"<0>fit</0> controls scaling: <1>fill</1>, <2>contain</2>, <3>cover</3>, <4>none</4>, or <5>scale_down</5>.\"],\"4XjRfU\":[\"Config-as-code\"],\"4eMock\":[\"Serves the canvas at a <0>mount</0> with a <1>latency_profile</1> hint.\"],\"4kOvII\":[\"Stacking order\"],\"4z65Wo\":[\"What the LIVE, STALE, RECONNECTING, and NO SIGNAL badges mean, and why the output never stalls on a bad input.\"],\"50I6Ez\":[\"Program bus only\"],\"5AU3Tn\":[\"Alarms matching the current filter.\"],\"5F876q\":[\"This permanently removes the profile's mapping rules.\"],\"5G1san\":[\"Configure output servers and renditions.\"],\"5N8BgZ\":[\"IEEE 1588 — distributing time over Ethernet from a grandmaster clock so every device agrees on \\\"now\\\" to about a microsecond. Under the SMPTE ST 2059 broadcast profile, frame boundaries are computable from the time itself, making PTP the IP facility's replacement for both genlock and timecode distribution.\"],\"5UxnFw\":[\"The default image encodes <0>mpeg2video</0> (plays in VLC or ffplay). For browser-friendly H.264 or H.265 output, use the <1>-gpl</1> image variant — note that H.264 / H.265 make the build GPL.\"],\"5WYZKZ\":[\"Search results\"],\"5Ykw8+\":[\"Create your first salvo\"],\"5bhON1\":[\"Bitrate\"],\"5ewIb7\":[\"Border width (px)\"],\"5lWFkC\":[\"Sign in\"],\"5rQuGz\":[\"Where the delay between a camera and your screen comes from, what each protocol adds, and the trade-offs against robustness.\"],\"5rzsl2\":[\"Very low (~1 frame)\"],\"5uJlyU\":[\"This is why the wall keeps running through any input failure: the output's timing is independent of every input by construction. Frame rates are handled as exact fractions (NTSC 29.97 is <0>30000/1001</0>, never a rounded decimal), so the cadence cannot drift over long runs.\"],\"5yVmvR\":[\"Volumes\"],\"6/dCYd\":[\"Overview\"],\"6AGZZM\":[\"Decode capacity is budgeted in megapixels per second — many small tiles can be cheaper than a few full-resolution ones.\"],\"6Aih4U\":[\"Offline\"],\"6NZOZv\":[\"Chroma subsampling\"],\"6OgW6G\":[\"An output is a sink/server that publishes the program.\"],\"6Q8OAK\":[\"/media/clip.mp4\"],\"6Vb68T\":[\"Over the layout drop zone.\"],\"6YtxFj\":[\"Name\"],\"6jAi8c\":[\"Range\"],\"6kCRXV\":[\"Notice\"],\"6oyg87\":[\"Could not load profiles:\"],\"6wsg8x\":[\"Wall-clock time\"],\"6yLC8p\":[\"Feature guide\"],\"72+i5c\":[\"<0>Timecode</0> — a per-frame <1>label</1> (HH:MM:SS:FF). Two feeds can carry identical timecode and still be out of phase — which is why genlock/PTP exist alongside it.\"],\"75iTY6\":[\"(opens in a new tab)\"],\"78EMRF\":[\"Element name\"],\"79ROKt\":[\"How configuration applies\"],\"7GJ4pe\":[\"Override cleared\"],\"7GcARX\":[\"GPU0\"],\"7L01XJ\":[\"Actions\"],\"7R4bEC\":[\"What transcoding is\"],\"7U3VdA\":[\"Layout saved; apply accepted\"],\"7Z9sDq\":[\"Loading audit log…\"],\"7a/K8s\":[\"Validation and import / export\"],\"7hktsm\":[\"Getting started\"],\"7p5kLi\":[\"لوحة القيادة\"],\"7rzvTP\":[\"No GPUs are reported on this host.\"],\"7tqL2x\":[\"Realtime streams\"],\"7zAWUq\":[\"Runnable\"],\"8+SjOh\":[\"Select cell\"],\"8+UyKi\":[\"Enter a whole number.\"],\"8668YJ\":[\"Could not load layouts:\"],\"8CtRtL\":[\"Good on LAN; not for WAN\"],\"8D1YM+\":[\"Could not export configuration\"],\"8F1i42\":[\"Page not found\"],\"8GD6sX\":[\"HDR\"],\"8IVuoS\":[[\"0\"],\" cell(s) · \",[\"1\"],\" bound to a source\"],\"8Lmm9O\":[\"e.g. program-hls\"],\"8MIU1T\":[\"Program\"],\"8NbHF7\":[\"Locale\"],\"8St6Zr\":[\"e.g. wall-clock\"],\"8Ug9jB\":[\"Related\"],\"8YtCMQ\":[\"RTMP\"],\"8cM4/C\":[\"Radius (px)\"],\"8ityWJ\":[\"The latency window is the key dial: it is the time budget SRT has to repair loss. A small window (~120 ms) keeps the feed snappy but tolerates little loss; a large window (1–4 s) rides out bad networks at the cost of delay. The payload is an MPEG transport stream, so codec choices follow the MPEG-TS rules.\"],\"8t1KsO\":[\"Enter a hex colour like #101014 or #abc.\"],\"8vQkDt\":[\"Latency\"],\"8y3GCK\":[\"The clock timezone offset must be a whole number between −720 and 840 minutes.\"],\"8zl7Th\":[\"RTSP carries whatever the camera encodes — usually H.264 or H.265 — so the picture quality and bitrate are set at the camera. It has no built-in recovery beyond TCP retransmission; on flaky links a stream simply stalls and must reconnect, which Multiview handles per tile without disturbing the rest of the wall.\"],\"9+qYNT\":[\"<0>Composite once, fan out many.</0> The canvas is encoded once per rendition and the same packets feed every transport, rather than re-encoding per destination.\"],\"9+u9xE\":[\"A codec is required for this output kind.\"],\"92S5fa\":[\"H.264 / AVC\"],\"99vx/w\":[[\"short\"],\" compute utilisation: ours \",[\"computeSelf\"],\" of \",[\"computeTotal\"],\" device total\"],\"9N81ke\":[\"Mutable resources carry an <0>ETag</0>. Send it back as <1>If-Match</1> on a write; a stale tag is rejected with <2>412 Precondition Failed</2> so two editors never silently clobber each other.\"],\"9NfzlL\":[\"Color spaces, limited vs full range, and HDR — and why a mismatch makes a tile look washed-out, crushed, or oddly tinted.\"],\"9cZ6iC\":[\"GPUs\"],\"9fgROz\":[\"The control plane serves an interactive OpenAPI reference at the backend <0>/docs</0> path. It is generated from the same spec the UI client is generated from, so it always matches the running server. Open it to browse every endpoint, see schemas, and try requests.\"],\"9kqqmM\":[\"The stack publishes the test RTSP feed on <0>8554</0> (for host inspection) and the HLS HTTP server on <1>8888</1>. There is no control-API or web-UI port yet: the current binary composites, encodes, and writes HLS or file output to disk, but does not yet bind a network listener. The live RTSP, NDI, and RTMP output <2>servers</2> and the API listener are on the roadmap.\"],\"9mz8CI\":[\"Left (%)\"],\"9plgCZ\":[\"Medium (~2–5 s)\"],\"9tH6zC\":[\"Salvo saved\"],\"9zb2WA\":[\"Connecting\"],\"AHFrAn\":[\"Modern GPUs and SoCs contain dedicated video engines — separate silicon for decode and encode that runs at a fraction of the power of a CPU doing the same work. Multiview uses them through each platform's standard interface: NVDEC/NVENC on NVIDIA, VAAPI on Intel and AMD (including Quick Sync), and VideoToolbox on Apple Silicon. With acceleration, decoding a wall of sources and encoding the canvas leaves the CPU almost idle; without it, a handful of HD decodes can saturate a machine.\"],\"Ai2U7L\":[\"Host\"],\"Aplgjb\":[\"Output path\"],\"AsqZm5\":[\"What transcoding actually is, the common video codecs, hardware acceleration, and how Multiview encodes its output.\"],\"B86Ri8\":[\"GPU 0 decoder utilisation trend\"],\"BB+RF8\":[\"Audit\"],\"BDHA/i\":[\"Severity\"],\"BGFNOX\":[\"HDR (High Dynamic Range)\"],\"BMR9sn\":[\"Genlock is the broadcast practice of locking every device's frame timing to one shared reference signal — historically an analog \\\"black burst\\\" or tri-level sync feed distributed around the facility. When everything is genlocked, every camera and every output starts its frames at the same instant, so video can be switched and mixed without glitches or re-buffering.\"],\"BaUuhR\":[\"Codec\"],\"BakXLg\":[\"Reconnecting\"],\"Bbx6YX\":[\"Override failed\"],\"BfGFUX\":[\"What transcoding is, the common video codecs, hardware acceleration, and the encode-once model.\"],\"BoFpfA\":[\"Multiview is a hardware-accelerated live video multiview generator. It ingests many live sources, composites them into a templated grid on the GPU, and serves the combined picture as a continuous output stream. It is designed for monitoring walls and production multiviewers where the output must never stall.\"],\"Bpj4fq\":[\"Replace the current cells?\"],\"BsEDQd\":[\"Every document starts with a <0>schema_version</0> and then declares the canvas, the layout strategy, the managed sources, the cells (tiles) that place those sources, overlays, and outputs. Optional blocks add fault probes, tally profiles, salvos, and video walls.\"],\"C0Rtr1\":[\"Could not load for editing\"],\"CAOI2N\":[\"New salvo\"],\"CJzOyM\":[\"Acknowledged\"],\"CQrqFD\":[\"About output transports\"],\"CRwklQ\":[\"Plain UDP has no recovery at all: a lost packet is a glitch on screen. That is acceptable on a managed facility LAN and wrong for the internet (use SRT there, which wraps the same transport stream in a recovering envelope). Multicast group management is IPv6-first: receivers join groups via MLDv2, with IPv4/IGMP as the legacy path.\"],\"CsLNMg\":[\"Configured output sinks.\"],\"Ctcpvf\":[\"Loading layouts…\"],\"D+NlUC\":[\"System\"],\"D07rgQ\":[\"As an input, HLS arrives in bursts (whole segments at a time), so Multiview paces it back to real time internally before it is sampled onto the wall. As an output it is the easiest way to let many people open the multiview in a browser or player.\"],\"D0qWby\":[\"canvas or a cell id\"],\"D63cXm\":[\"Cells (accessible)\"],\"DB8zMK\":[\"Apply\"],\"DHXxFa\":[\"<0>NDI:</0> about a frame on a fast LAN — the lowest of the supported transports.\"],\"DIjGmJ\":[\"Delete source\"],\"DJCC48\":[\"Push to/from streaming platforms\"],\"DMInEh\":[\"Anywhere HTTP works, CDN-scalable\"],\"DTAxdY\":[\"المخرجات\"],\"DTuwpO\":[\"The API authenticates each request with a bearer token in the <0>Authorization</0> header. A coarse role (admin, operator, or viewer) gates what actions a token may take, and a per-object check confines a token to the resources it owns.\"],\"DelmEd\":[\"This toast is announced to assistive technology.\"],\"DfXj2D\":[\"The fastest way to see Multiview running is the quick-start compose stack. It publishes a synthetic test feed, composites a 2x2 canvas, and serves the result over HTTP so you can open it in a player — no real cameras or private feeds required.\"],\"DfmatK\":[\"Running in containers\"],\"Dfz/mG\":[\"<0>Live RTSP / NDI / RTMP / SRT servers and push.</0> The network output servers are not yet wired into the run command.\"],\"Dmjdyv\":[\"e.g. cam-north\"],\"DyQpnZ\":[\"Loading outputs…\"],\"E/QGRL\":[\"Disabled\"],\"E3V6qr\":[\"The compose stack uses a real liveness check: the HLS playlist must have been rewritten within the last 30 seconds. Because the segmenter rewrites the playlist every segment, a fresh timestamp proves the output clock is still producing frames. The check uses only coreutils, so it works on the slim runtime.\"],\"E6uSKB\":[\"RTSP, NDI, SRT, RTMP, HLS, MPEG-TS, and files: how each carries video and which to use where.\"],\"EIrE3l\":[\"Index\"],\"EOKvQU\":[\"Leave empty for all objects\"],\"ESrkAW\":[\"MLDv2\"],\"Ebgt1X\":[\"Stable device id\"],\"EdQY6l\":[\"None\"],\"EhidQ5\":[\"Preview of input \",[\"0\"]],\"Enslfm\":[\"Destination\"],\"EwSTaG\":[\"Theme: dark. Switch to system.\"],\"F16NQI\":[\"Tally binding (optional)\"],\"F5fT8R\":[\"GPU acceleration is opt-in. The compose stack ships two overlay files that add the right device access; you can apply the same settings to a plain <0>docker run</0>.\"],\"F6Ugpv\":[\"Every cell needs a non-empty identifier.\"],\"FBhPhU\":[\"The identifier is fixed once created. Source, tally, and UMD recall clauses already on this salvo are preserved when you save.\"],\"FE9zOA\":[\"Loading salvos…\"],\"FEr96N\":[\"Theme\"],\"FIyFBA\":[\"A software fallback always exists, so a build without any GPU still works — just with less headroom.\"],\"FKPgi7\":[\"The <0>[layout]</0> block selects how cells are placed, tagged by <1>kind</1>:\"],\"FSbpS7\":[\"CPU\"],\"FSqTcV\":[\"Any severity\"],\"FZmmyT\":[\"This permanently removes the resource. Running outputs are not affected until a new configuration is applied.\"],\"FiKi/8\":[\"Advertise the canvas as an NDI source by <0>name</0>.\"],\"FlHrgR\":[\"The UI subscribes to engine events for tile states, operation results, alarms, and telemetry. These streams are strictly best-effort: they can drop or conflate events under load and are physically incapable of slowing the engine, so a client must tolerate gaps and reconcile against the REST state.\"],\"Fo2bwm\":[\"Actor\"],\"Fpt69l\":[\"Locator\"],\"G866mV\":[\"Requires the NVIDIA driver and the NVIDIA Container Toolkit on the host. The modern path requests devices through CDI; NVENC and NVDEC also need the <0>video</0> driver capability.\"],\"GBncI8\":[\"Canvas width in pixels.\"],\"GO4HNP\":[\"Explicit track list\"],\"GYxHDZ\":[\"Saved as \",[\"0\"],\". Restart Multiview with this file to apply stored changes.\"],\"GaPZXV\":[\"Could not load alarms:\"],\"Gd5XDR\":[\"Enter a whole number within the allowed range.\"],\"GfyNcv\":[\"Robustness\"],\"Gl5yGd\":[\"Live tiles from the engine stream.\"],\"GoNjkn\":[\"Minimum severity\"],\"Gv683U\":[\"الطبقات\"],\"GwwX42\":[\"This layout uses a grid or preset placement that the free-form editor cannot modify yet. Editing is read-only.\"],\"H1MkIq\":[\"Not in the running engine — no live state until a config export + restart binds it to a tile.\"],\"HSmJFV\":[\"VRAM\"],\"HWpPGm\":[\"GPU\"],\"HqRbXG\":[\"PROG\"],\"HtFS9P\":[\"Design pillars\"],\"Hvq0fm\":[\"Height (%)\"],\"I5PX3G\":[\"Profile deleted\"],\"ICpFWC\":[\"Multiview layouts. The accessible editor offers a form-based path equivalent to the drag-and-drop canvas. Apply is live on the running engine.\"],\"IE5dk2\":[\"Lamp\"],\"IGdU0V\":[\"No frame-rate sample.\"],\"IIG1n7\":[\"The low-latency extension of HLS: segments are published in partial chunks and players can request the next part before it is finished, cutting typical delay from 6–30 s to roughly 2–5 s while keeping plain-HTTP delivery and CDN scalability.\"],\"IJyMMV\":[\"Apply filter\"],\"ILFKMg\":[\"Could not apply layout\"],\"ILG22U\":[\"Canvas height in pixels.\"],\"IV0EjT\":[\"Test notification\"],\"IXxHr+\":[\"Our NVENC sessions / device-wide sessions / ceiling\"],\"IfIpuo\":[\"No inputs are available to preview.\"],\"IfKlGj\":[\"AV1 is the open, royalty-free codec developed by the Alliance for Open Media. It compresses better than HEVC and has fast hardware decode support arriving across recent GPUs and devices, with hardware encoding available on the newest generations. For live work its software encoders are still heavy, so AV1 is the right choice when the audience's players are known to support it and bandwidth is at a premium.\"],\"IhHxAl\":[\"Push the encoded stream to a destination <0>url</0>.\"],\"IpMP5d\":[\"Override the detected colour metadata\"],\"Is0On1\":[\"Whole minutes between −720 and 840 (e.g. 600 = UTC+10).\"],\"IxhDBR\":[\"Encode once, fan out many\"],\"Ixuaol\":[\"A locator is required for this source kind.\"],\"J1WYKN\":[\"In a multiview chain there are two transports in the path: the one each source arrives on, and the one the composed wall goes out on. Both choices matter, and they are independent — a wall of low-latency RTSP cameras served out over plain HLS is still tens of seconds behind for its viewers.\"],\"J5nbej\":[\"Critical\"],\"JXDtPG\":[\"MPEG-TS / UDP multicast\"],\"JrFTcr\":[\"Connecting…\"],\"JvHAFh\":[\"This overlay kind has no configurable parameters in this build. Parameters authored in a config file are preserved unchanged.\"],\"K/F6pa\":[\"Saving…\"],\"K5mlJI\":[\"Loading canvas…\"],\"KE0/FX\":[\"SRT\"],\"KHJSuk\":[[\"short\"],\" compute utilisation \",[\"computeTotal\"],\" (device total)\"],\"KLCB0R\":[\"The default image encodes <0>mpeg2video</0>, which plays in VLC and ffplay. For browser playback, switch to the GPL image and an H.264 codec (see the config section).\"],\"KSCnVQ\":[\"Kind\"],\"KdnqAo\":[\"1+5\"],\"KgG1nS\":[\"Each <0>[[cells]]</0> entry is one tile. It is placed by a grid <1>area</1> or an absolute <2>rect</2>, and binds a source through <3>[cells.source]</3> — usually a reference to a managed source by <4>input_id</4>.\"],\"KmVL2j\":[\"The management API, its conventions, the realtime event streams, and where to find the live, interactive reference.\"],\"KqFD1b\":[\"A source is a managed input. Each one owns its ingest, decode, color handling, and reconnect behaviour, and is referenced by tiles via a stable id. Supported kinds include RTSP, HLS, MPEG-TS, SRT, RTMP, NDI, file, and a built-in synthetic test pattern. When a source stops delivering frames, its tile holds the last good frame and moves through a clear state machine — live, stale, reconnecting, no-signal — while the engine reconnects without disturbing the rest of the wall.\"],\"Kqg7nZ\":[\"About the tile lifecycle\"],\"Kv3evY\":[\"Download the current stores (sources, outputs, overlays, layouts, canvas) as multiview.toml. Stored UI edits take effect when Multiview restarts with this file; live actions (apply layout, swap, routing, salvos) act on the running engine immediately.\"],\"L2CVk3\":[\"Skip to content\"],\"L35PNQ\":[\"<0>Low-latency HLS.</0> Partial-segment HLS for lower glass-to-glass latency.\"],\"L7QOgA\":[\"The engine. It ingests that feed plus three built-in test patterns into a 2x2 canvas, encodes once, and writes HLS to a named volume.\"],\"LA6ADb\":[\"Tally\"],\"LAOD9x\":[\"NVENC encode sessions trend\"],\"LBfiH5\":[\"New cell\"],\"LN3cv8\":[\"A mount point must start with /, e.g. /multiview.\"],\"LQn3sm\":[\"The cell is too small.\"],\"LS5fp9\":[\"Full content interpreted as limited: shadows <0>crush to solid black</0> and highlights clip to white.\"],\"La2Gp2\":[\"Failures use RFC 9457 problem documents (<0>application/problem+json</0>) with a machine-readable type and a human-readable detail.\"],\"LbnHlN\":[\"<0>Control never back-pressures the engine.</0> The management API, realtime streams, and preview are best-effort and physically incapable of stalling the output path.\"],\"Ln1gZf\":[\"Seed from a preset\"],\"Ls/uE1\":[\"Multiview layouts. The accessible editor offers a form-based path equivalent to the drag-and-drop canvas.\"],\"LxsoLZ\":[\"Engine default (mixed program bus)\"],\"M/Q2aG\":[\"Open navigation\"],\"MFY72u\":[\"An RTMP URL must start with rtmp:// (or rtmps://).\"],\"MJ+dU7\":[\"<0>WebSocket</0> (primary) at <1>/api/v1/ws</1> — bidirectional, used for the live UI.\"],\"MMowHm\":[\"Live API playground\"],\"MTJyja\":[\"The timestamp on each frame saying when it should be shown. Real-world streams wrap, jump, and reset their PTS, so Multiview normalizes every input's timestamps onto one internal timeline and stamps its output purely from its own output clock — raw input timestamps never reach the output.\"],\"MTrkXx\":[\"File path\"],\"Ma3BY+\":[\"Bit→colour rules\"],\"MbRyzp\":[\"Definition\"],\"MkjyGy\":[\"Track id or language tag\"],\"MlRvJr\":[\"None (no captions decoded)\"],\"MnwC6r\":[\"That layout no longer exists.\"],\"Mybo2L\":[\"Studio sources, production fabric\"],\"N30D8d\":[\"Document shape\"],\"NDuIft\":[\"All configured salvos.\"],\"NLMCIp\":[\"API & realtime\"],\"NLYmhh\":[\"The text label strip under (or on) each tile showing the source name — named for the physical display modules mounted under monitors in traditional galleries. UMD text can be static or driven dynamically by a router or automation system.\"],\"NShyDs\":[\"Locator URL\"],\"NqnAYa\":[\"No host-memory sample.\"],\"NtMzGO\":[\"Letting many viewers watch the composed wall: HLS, or LL-HLS when delay matters.\"],\"NvVUzv\":[\"Override accepted\"],\"O307N1\":[\"Pin encode to a specific GPU\"],\"O3vwyx\":[\"Could not load overlays:\"],\"O5GAmY\":[\"Create your first layout\"],\"OJ7BG3\":[\"Layouts, sources, outputs, overlays, tally, salvos, and alarms — what each one is.\"],\"OM20Fb\":[\"The MPEG transport stream is the container broadcast infrastructure speaks: a self-synchronizing packet format that multiplexes video, audio, subtitles, and data on numbered PIDs. Sent over UDP — usually to a multicast group so one sender feeds any number of receivers on the network — it is the classic in-facility distribution method, with latency well under a second.\"],\"ONGF1b\":[\"What each protocol adds\"],\"OWqxh7\":[\"GPU 0 VRAM usage trend\"],\"Oa+C3O\":[\"Alarm acknowledged\"],\"OdeTRK\":[\"Delete this resource?\"],\"Oer+Gg\":[\"Subtitle track (id / language)\"],\"Ogm+FQ\":[\"Color management\"],\"OsEkWl\":[\"Could not create\"],\"OuNBvf\":[\"Segment duration (ms, optional)\"],\"P/8eNo\":[\"Edit layout\"],\"P/yGyM\":[\"Add cell\"],\"P0Gv/N\":[\"Inputs are sampled, never trusted to pace the output. A single fixed-cadence clock emits exactly one frame per tick. When a source drops, its tile holds its last good frame and shows a clear state while the engine reconnects in the background — the rest of the wall keeps running.\"],\"P0H6jK\":[\"Last-good frames\"],\"P4K3bP\":[\"Discard the source wall-clock\"],\"P8fBlG\":[\"Authentication\"],\"PApEJe\":[\"Custom…\"],\"PF860N\":[\"Face\"],\"PKy/EA\":[\"A solid source needs a hex colour like #101014 or #abc.\"],\"PLpF5v\":[\"HLS (HTTP Live Streaming) delivers video as a playlist of small media segments over plain HTTP. That makes it the most firewall-friendly and scalable transport — any web server or CDN can fan it out to thousands of viewers — at the cost of latency: a player typically starts several segments behind the live edge, so 6–30 seconds of delay is normal. Low-Latency HLS (LL-HLS) publishes partial segments and lets players request the next part before it is complete, bringing latency down to roughly 2–5 seconds while keeping HTTP delivery.\"],\"POGHob\":[\"PTS (Presentation Timestamp)\"],\"PVTnyn\":[\"Requests will be unauthenticated.\"],\"PWZeOA\":[\"A reference only — never a plaintext secret. Leave blank for none.\"],\"PcuAyk\":[\"Multiview\"],\"PeX+aI\":[\"Default software image. Also carries the VAAPI userspace and Mesa or Intel drivers, so it can use an Intel or AMD render node when one is passed through.\"],\"Pg6/UH\":[\"Configuration export\"],\"PtfGH1\":[\"Intel\"],\"Pwqkdw\":[\"Loading…\"],\"Py7Lpq\":[\"Captions\"],\"Q7Z4HQ\":[\"The UI will authenticate with this token.\"],\"QHcLEN\":[\"Connected\"],\"QKkqUz\":[\"Command failed\"],\"QM09rm\":[\"LL-HLS (Low-Latency HLS)\"],\"QNMDLS\":[\"Jitter buffer\"],\"QRG5DS\":[\"Loading sources…\"],\"QSsdWA\":[\"Wall-clock time is ordinary time-of-day (UTC), kept by the host's system clock and disciplined by NTP or PTP. Multiview uses it for <0>labels only</0>: on-screen clock overlays, log timestamps, and the date-time stamps in HLS playlists. It never paces frames, because a system clock can step backwards or jump when corrected — exactly what an output clock must never do.\"],\"QsDjlD\":[\"Apple\"],\"QxvFiZ\":[\"Appearance and language preferences.\"],\"R/QmBR\":[\"Manage overlay layers and subtitles.\"],\"R3y75Z\":[\"Edit source\"],\"R4xfhx\":[\"Active and cleared\"],\"R5Rk3n\":[\"Could not load salvos:\"],\"RFK+0u\":[\"Tile status\"],\"RJhOD1\":[\"Loss recovery + encryption\"],\"RLe7Vk\":[\"Checking…\"],\"RS0o7b\":[\"State\"],\"RSE4AO\":[\"Genlock\"],\"RX1wIv\":[\"No overlays configured.\"],\"RaZAKo\":[\"No GPU reported\"],\"RbvMp/\":[\"Why the output clock never depends on inputs\"],\"Rg4F+3\":[\"Backward\"],\"RgOX4N\":[\"Could not acknowledge alarm\"],\"RhHfNK\":[\"Delete output\"],\"Rhpo4J\":[\"Each <0>[[sources]]</0> entry is a managed input with a stable <1>id</1>, an optional <2>display_name</2>, and a <3>kind</3> that selects the transport. The network kinds carry a <4>url</4>; NDI binds by <5>name</5>; file inputs use a <6>path</6>; <7>test</7> is a built-in synthetic pattern with no parameters.\"],\"Rm030K\":[\"A tiny nginx that serves the HLS volume over HTTP so you can open the stream in a player at <0>http://[::1]:8888/multiview.m3u8</0>.\"],\"RxzN1M\":[\"Enabled\"],\"S+VdK1\":[\"Switch the interface language and text direction.\"],\"S4oMJ5\":[\"Program output frame rate trend\"],\"SG9Eoc\":[\"Exposed ports and roadmap\"],\"SGKq6q\":[\"H.265 / HEVC\"],\"SI6RLy\":[\"Enter a valid target\"],\"SMPmx2\":[\"A CSS-grid layout with <0>columns</0> and <1>rows</1> track lists (<2>fr</2> / <3>px</3> / <4>%</4>), a <5>gap</5>, and an <6>areas</6> map that names where each cell sits.\"],\"SQJk7h\":[\"Engine default (reclock to house)\"],\"SSSzDH\":[\"Glossary: PTP\"],\"SUcgdl\":[\"Very low (<1 s)\"],\"SUu491\":[\"Locking every device's frame timing to one shared reference signal so all frames start at the same instant across a facility. Classically an analog black-burst or tri-level signal; in IP facilities PTP carries the same role. Genlock aligns <0>phase</0>; timecode merely labels frames.\"],\"SaghVL\":[\"Last-good frame\"],\"SkU82R\":[\"RTMP is a TCP push protocol that remains the lingua franca for sending a stream <0>to</0> a service — most streaming platforms still ingest it. Classic RTMP carries H.264 video and AAC audio only; newer \\\"enhanced\\\" endpoints negotiate H.265 and AV1. As an input it appears when an encoder or app pushes to Multiview; as an output it is how Multiview pushes the composed canvas to a platform.\"],\"Smc0q0\":[\"LAN / routed networks\"],\"SmzQ++\":[\"DVB teletext page\"],\"SqayOc\":[\"HLS and LL-HLS\"],\"SrA7Jc\":[\"The output clock, genlock, PTP, and wall-clock time — how frames are paced and aligned.\"],\"StOkj1\":[\"An overlay is a layer composited over the program at a stacking order.\"],\"Su3Ivq\":[\"A destination is required for this output kind.\"],\"Svm2tF\":[\"No tally targets are reporting a lamp state.\"],\"T/R+Qz\":[\"Primary\"],\"T1Ueop\":[\"Two image families are published. The default image is LGPL-clean and software-only; the NVIDIA image adds CUDA-based decode, encode, and compositing.\"],\"T7Iu0d\":[\"The amount of data a stream uses per second, usually in megabits per second (Mb/s). For a given codec, more bitrate means better picture quality and more bandwidth used. Encoders trade bitrate against quality and resolution; a multiview canvas is typically encoded at one fixed bitrate per rendition.\"],\"T9gYz0\":[\"No layouts are defined yet.\"],\"TBLoEc\":[\"A small receive-side buffer that absorbs the uneven arrival of network packets so frames can be consumed smoothly. Deeper buffers ride out worse networks but add latency. Each Multiview input has its own bounded buffering; an overflowing input drops its oldest data rather than growing without limit.\"],\"TK7HtE\":[\"Live host and accelerator utilisation streaming from the engine.\"],\"TPbg6n\":[\"The working color space. <0>profile</0> names a preset (e.g. <1>sdr-bt709-limited</1>); <2>custom</2> lets you set primaries, transfer, matrix, and range explicitly.\"],\"TV/7QJ\":[\"Active and historical faults the engine raised. Acknowledge an alarm to record that an operator has seen it.\"],\"TVqUdZ\":[\"Code:\"],\"TZeMq8\":[\"Decoding compressed video and recompressing it into a different codec, resolution, or bitrate. Each transcode costs quality (a new lossy generation), latency, and compute, so well-designed systems transcode once and reuse the result everywhere.\"],\"TbjyhA\":[\"Docs\"],\"Tq8iSD\":[\"Cell identifiers must be unique within a layout.\"],\"Tr24ga\":[\"Salvos\"],\"TvY/XA\":[\"Documentation\"],\"Tz0i8g\":[\"الإعدادات\"],\"Tzz0Y5\":[\"Compose merges files left to right. The GPU overlay files swap the <0>multiview</0> image and add device access; the other services are inherited unchanged. Layer an overlay on top of the base file:\"],\"U/VAf2\":[\"All endpoints live under <0>/api/v1</0>.\"],\"U9NXL4\":[\"A Multiview deployment is one declarative document. It is authored as TOML and round-trips losslessly to JSON (the API wire form).\"],\"UEOZgY\":[\"Bus\"],\"UN8QEt\":[\"Loading layout…\"],\"UXu//X\":[\"Testing, placeholders, layout work\"],\"UeeR1Q\":[\"A per-cell <0>qos</0> block sets a degradation <1>priority</1> and strategy, so the engine sheds the cheapest tiles first under load before touching the program output.\"],\"UefSvM\":[\"Encoder utilisation: ours over device total\"],\"Ui1L1e\":[\"No audit entries match.\"],\"UirGxE\":[\"Errors\"],\"Uki3yG\":[\"This Multiview control plane requires an API key. Paste your admin or operator key to continue.\"],\"UmA5du\":[\"A multiviewer is inherently a transcoder: it must decode every source to composite them into one canvas, and then encode that canvas for its outputs. What it never does is transcode each tile separately — the cost would multiply by the number of tiles for no benefit.\"],\"UoqckY\":[\"Export configuration\"],\"UvzFI5\":[\"RTSP transport\"],\"UwqoLj\":[\"This field is required.\"],\"UxKoFf\":[\"Navigation\"],\"UzbJVx\":[\"Wide distribution, browser viewing\"],\"V+xf8u\":[\"File / synthetic\"],\"V0XqG/\":[\"In this UI, set your token under Settings, then API access. For a container, supply it as the <0>MULTIVIEW_CONTROL_TOKEN</0> environment variable — the presented token is <1>admin.<secret></1>. When that variable is unset, the server generates a token and logs it once at startup. The unauthenticated surface is just <2>/</2>, <3>/docs</3>, and <4>/api/v1/openapi.json</4>; every <5>/api/v1</5> data route requires the token.\"],\"V2ApNh\":[\"NVENC sessions\"],\"V4bkAo\":[\"The moment a fresh frame arrives — from any state — the tile snaps straight back to LIVE. The hold, stale, and no-signal windows are configurable per deployment.\"],\"V5EUiI\":[\"Watch / live / channel URL\"],\"V7994R\":[\"RTSP\"],\"V96jYV\":[\"Search docs…\"],\"VJe7Q1\":[\"New source\"],\"VKrn7F\":[\"The unauthenticated surface is just <0>/</0>, <1>/docs</1>, and <2>/api/v1/openapi.json</2>; every <3>/api/v1</3> data route requires the token. The image must be built with the <4>web</4> feature for the UI to be embedded (the published image is).\"],\"VLHErN\":[\"Hardware encoders also sidestep the GPL obligation of the software H.264/H.265 encoders, keeping the default build license-clean.\"],\"VS9ghV\":[\"auto\"],\"VfSoIA\":[\"<0>HLS:</0> 6–30 s — players deliberately start several segments behind the live edge. <1>LL-HLS</1> brings this to roughly 2–5 s with partial segments.\"],\"Vg4Lnw\":[\"No drop target.\"],\"VilJlE\":[\"Compute utilisation (device total)\"],\"VmkjGB\":[\"Green\"],\"Vng0SN\":[\"Apply layout to engine\"],\"Vnyj+M\":[\"The external tally state that drives this border.\"],\"VtIVQ9\":[\"API token\"],\"VwHF5R\":[\"No outputs configured.\"],\"VwrDU4\":[\"Fresh frames are arriving; the tile shows the newest one. This is the normal state.\"],\"Vzk6QZ\":[\"A layout name is required.\"],\"W034oz\":[\"Decoder\"],\"W0i24j\":[\"Object\"],\"WBfixh\":[\"No sources configured.\"],\"WC1PzK\":[\"The source has been quiet long enough that the engine is actively re-establishing it. The tile still shows the last good frame, now with a reconnect indicator, so an operator can tell a frozen feed from a live one.\"],\"WJ+zFC\":[\"Canvas width and height must be positive whole numbers.\"],\"WOqmP+\":[\"Broadcast and streaming terms used across Multiview, alphabetized. Use the documentation search to jump straight to a term.\"],\"WYz2DT\":[\"API access token\"],\"WZZ5Ab\":[\"Search documentation\"],\"WjEGTf\":[\"Fix these before saving:\"],\"WvJDOC\":[\"Latency class\"],\"Wx0xW/\":[\"Network fit\"],\"WxVNOC\":[\"Working pixel format: <0>nv12</0> (8-bit) or <1>p010</1> (10-bit).\"],\"WxqfPL\":[\"Trade-offs\"],\"WybtSl\":[\"CPU utilisation trend\"],\"WzHDGF\":[\"Removed from the store. The running engine is unchanged until a config export + restart.\"],\"X+NMLG\":[\"Take\"],\"X0l3Fn\":[\"A salvo is a named, atomically-applied recall. One salvo can switch the layout, rebind sources into cells, set tally colors, and update under-monitor display text — all at once — so an operator can move a whole arrangement (say, a VTR review setup) with a single action instead of a series of separate edits.\"],\"X4wlbj\":[\"Credentials secret reference\"],\"X6ssOp\":[\"Could not delete layout\"],\"XCRGjd\":[\"Tile index\"],\"XI2p1D\":[\"Add and manage live ingest sources.\"],\"XLX6aB\":[\"VRAM used of total\"],\"XM8qlK\":[\"Choosing a transport\"],\"XR/hoT\":[\"Could not save salvo\"],\"XSqIIp\":[\"<0>HLS / file output.</0> Writes a playlist and segments to disk. This is the path the quick-start uses and that works today.\"],\"XVombj\":[\"Tally shows which sources are on-air. A tally profile maps the bits of an external tally bus to colors (for example red for program, green for preview) and maps bus index positions to specific tiles. A <0>tally_border</0> overlay then lights the tile's edge to match. This lets an upstream router or mixer drive the borders on the wall.\"],\"XdweLI\":[\"Very high (plain HTTP)\"],\"XflxsY\":[\"A feed crossing the internet: SRT (tune the latency window to the link).\"],\"XmVc+G\":[\"Decide who needs low latency. An operator wall watching for faults wants seconds at most; overflow viewing in a browser can tolerate plain HLS.\"],\"Xv3Tgs\":[\"Fast production LAN\"],\"YDF0DU\":[\"Active NVENC sessions out of the discovered ceiling\"],\"YH2yyl\":[\"NDI (Network Device Interface) is a production-LAN video transport: senders announce themselves on the network, receivers discover them by name, and video flows with very low latency (around a frame) at high bitrates using NDI's own lightweight codec. There are no URLs to manage — a source is selected by its advertised name.\"],\"YHsgX+\":[\"Alarms\"],\"YP5oa6\":[\"Operation id\"],\"Yj3duQ\":[\"Cells\"],\"Yj7A0P\":[\"3×3\"],\"Yrrg+y\":[\"Target\"],\"Yu6Ow8\":[\"Multiview Program\"],\"YxQgK/\":[\"Could not save layout\"],\"Z4qiTR\":[\"Mount point\"],\"ZByQ6w\":[\"Each <0>[[overlays]]</0> entry attaches a layer to the whole <1>canvas</1> or to a single cell. Common kinds are <2>clock</2>, <3>label</3>, and <4>tally_border</4>. Kind-specific parameters (such as a clock <5>format</5>) sit alongside the common fields and round-trip losslessly.\"],\"ZCfSno\":[\"RECONNECTING\"],\"ZE984G\":[\"About the encode-once output model\"],\"ZFMR23\":[\"A named factory arrangement: <0>2x2</0>, <1>3x3</1>, <2>1+5</2>, or <3>pip</3>.\"],\"ZHjHId\":[\"Rotation must be between 0 and 359 degrees.\"],\"ZKwuuN\":[\"12-hour clock\"],\"ZYnwzF\":[\"Disconnected\"],\"ZkGS/T\":[\"The requested screen does not exist.\"],\"ZsUYln\":[\"Manual override\"],\"Zty/IJ\":[\"Canvas\"],\"a3ZWKA\":[\"How to fix:\"],\"a4It7U\":[\"Width (%)\"],\"a4N143\":[\"The signalling that shows which sources are on-air: classically a red light on the program camera and green on preview. On a multiview wall, tally renders as colored borders around tiles, driven by an upstream switcher or router.\"],\"aAIQg2\":[\"Appearance\"],\"aBgwis\":[\"Scope\"],\"aL1w5Z\":[\"Used\"],\"aMrLV8\":[\"docker run\"],\"aNNMsD\":[\"Top (%)\"],\"aNvzrp\":[\"List at least one track name (comma-separated).\"],\"aVEgLJ\":[\"The output canvas: geometry, cadence, working pixel format, background, and color space.\"],\"aWGl7Z\":[\"An identifier is required.\"],\"aYiOmp\":[\"Sidecar file (SRT/WebVTT)\"],\"af8o1u\":[\"PTP (IEEE 1588) is genlock's IP-network successor. A \\\"grandmaster\\\" clock distributes time over ordinary Ethernet, and every device on the network disciplines its own clock to it — typically to within a microsecond. The broadcast profile, SMPTE ST 2059, adds the convention that frame boundaries are computable from the time itself, so two PTP-locked devices agree not just on the time of day but on exactly when each frame starts. This single mechanism replaces both the genlock signal (phase) and timecode distribution (labels) in an IP facility, and is the timing backbone of SMPTE ST 2110 installations.\"],\"afd35O\":[\"Cell name\"],\"ah/qNy\":[\"Auto (first usable track)\"],\"aiZw2C\":[\"The MPEG transport stream container used throughout broadcast: fixed 188-byte packets multiplexing video, audio, subtitles, and data on numbered PIDs, designed to stay decodable through noise and joins. Carried over UDP/multicast in facilities and inside SRT across the internet.\"],\"ajwhvs\":[\"Decoder utilisation: ours over device total\"],\"an5hVd\":[\"Images\"],\"aoVIEM\":[\"Resolved state\"],\"apZW+s\":[\"Delete salvo?\"],\"az8lvo\":[\"Off\"],\"b+acLv\":[\"GOP (ms)\"],\"b66k1G\":[\"Network Device Interface — a production-LAN video transport in which senders advertise themselves by name and receivers discover them automatically. Near-frame latency at mezzanine quality, at the cost of high bandwidth and LAN-only reach.\"],\"b7qL3Q\":[\"A layout decides where every tile sits on the canvas. Use a factory preset (such as 2x2 or 1+5), a CSS-grid with named areas and fractional tracks, or absolute normalized rectangles for full control. A cell's fit mode controls how a source is scaled into its tile — contain to letterbox, cover to crop and fill, or fill to stretch.\"],\"bIsskZ\":[\"The quick-start file at <0>deploy/compose.yaml</0> brings up three services. It is self-contained — no real or private feeds.\"],\"bJFng6\":[\"Compute utilisation: ours over device total\"],\"bPiVFZ\":[\"Seed cells from preset\"],\"bV09j5\":[\"admin.xxxxxxxx-xxxx-…\"],\"bVhvzL\":[\"NVENC\"],\"baSIOg\":[\"Latency & protocol guide\"],\"bgxTc7\":[\"Credentials are referenced, never inlined: <0>auth</0> holds a <1>secret_ref</1> pointer, not a plaintext secret.\"],\"bloDiy\":[\"Open the system metrics page\"],\"bp3nYW\":[\"The TOML schema: canvas, layout, sources, cells, overlays, and outputs.\"],\"bp5nTD\":[\"Reconnect behaviour\"],\"bv4cFj\":[\"Transport\"],\"bwRvnp\":[\"Action\"],\"c/fYyN\":[\"Replace cells\"],\"c8hDKV\":[\"Codecs & transcoding\"],\"cBK6DE\":[\"Theme: light. Switch to dark.\"],\"cHHEpD\":[\"All configured layouts.\"],\"cHyNSu\":[\"Color spaces, limited vs full range, and HDR — why mismatches look washed-out or crushed.\"],\"cIeokf\":[\"Which transports carry which codecs\"],\"cKXWX6\":[\"Concepts\"],\"cN8jw8\":[\"Base path\"],\"cOjcew\":[[\"short\"],\" NVENC encode sessions trend\"],\"cP1rc+\":[\"H.265 (HEVC) compresses roughly 30–50% better than H.264 at the same quality, which matters most at 4K and for 10-bit/HDR content. The trade-offs: encoding costs more compute, patent licensing is more complicated, and playback support — while now broad on hardware — is still patchier in browsers than H.264. Classic RTMP cannot carry it; newer endpoints and MPEG-TS based transports can.\"],\"cPDR63\":[\"The three services\"],\"cnGeoo\":[\"Delete\"],\"cnkhyM\":[\"Seeding from a preset replaces every cell in this draft. Nothing is saved until you save the layout.\"],\"co5/Z1\":[\"About source transports\"],\"cpVZTy\":[\"A salvo id is required\"],\"cpdS45\":[\"The Real Time Streaming Protocol — the standard way IP cameras and encoders serve a live stream by URL (for example <0>rtsp://camera.local:8554/main</0>). The control channel negotiates the session and the media flows as RTP, over UDP or interleaved in TCP, with latency well under a second.\"],\"cpt677\":[\"Live program output and per-input previews, with each tile's lifecycle state from the engine stream.\"],\"csDS2L\":[\"Available\"],\"d+F6q9\":[\"Created\"],\"d4oCa9\":[\"Bring it up and down\"],\"d69Vr8\":[\"e.g. Main wall\"],\"d6h6zi\":[\"Loading alarms…\"],\"d6oxNG\":[\"Multicast Listener Discovery version 2 — the IPv6 protocol a receiver uses to tell the network which multicast groups (and, with source-specific multicast, which senders) it wants. It is the IPv6 successor to IPv4's IGMP and the primary group-join mechanism in Multiview's IPv6-first multicast support.\"],\"dAFyQ4\":[\"No signal\"],\"dAUy6B\":[\"Edit output\"],\"dBJess\":[\"<0>MPEG-TS / UDP multicast:</0> well under a second on a managed network (no recovery buffering at all).\"],\"dDcsWZ\":[\"Whether pixel values use the limited \\\"TV\\\" scale (black at 16, white at 235 in 8-bit) or the full \\\"PC\\\" scale (0–255). Reading a stream with the wrong range makes it look washed-out (limited read as full) or crushed (full read as limited). One of the most common picture-quality faults in any video chain.\"],\"dDoHhx\":[\"Acknowledge\"],\"dEgA5A\":[\"Cancel\"],\"dF6vP6\":[\"Live\"],\"da2Sq7\":[\"<0>Output clock</0> — decides <1>when</1> each frame is emitted (monotonic, fixed cadence).\"],\"dcLS/S\":[\"<0>Server-Sent Events</0> (fallback) at <1>/api/v1/events</1> — one-way, for environments where a WebSocket cannot be used.\"],\"dgs/Rt\":[\"The quick-start compose stack, the services it defines, the GPU overlays, and how to bring it up and down.\"],\"djj7Aq\":[\"None (local)\"],\"dm/ru0\":[\"Low-latency HLS, adding <0>part_target_ms</0> and <1>gop_ms</1> tuning.\"],\"dwU4ht\":[\"Layout saved\"],\"e8usQy\":[\"Frame rate\"],\"ePK91l\":[\"Edit\"],\"ecWZWa\":[\"About layouts\"],\"edXQdr\":[\"This screen is part of an upcoming milestone.\"],\"edz5/s\":[\"The most recent valid frame a tile has received, held on screen whenever its source hiccups so a brief dropout is invisible. Tiles escalate from holding the last-good frame to a reconnect indicator and finally a \\\"no signal\\\" slate if the source stays away.\"],\"eonHLC\":[\"Live program output\"],\"f/3VTC\":[\"Command accepted\"],\"f/M9l6\":[\"No source\"],\"f7VMs9\":[\"Being plain TCP, RTMP has no loss-recovery tuning: on a poor link it buffers and falls behind rather than dropping. Latency is typically a few seconds.\"],\"f7tleJ\":[\"Enter a whole number greater than zero.\"],\"fCPQJn\":[\"Not yet runnable in this build\"],\"fJ3m3/\":[\"Managed facility LAN\"],\"fOpR7k\":[\"API token cleared\"],\"feB1LA\":[\"A target is required.\"],\"fiKej8\":[\"Could not delete profile\"],\"fpMs2Z\":[\"LIVE\"],\"fqHp6v\":[\"Link to section\"],\"frRgOj\":[\"No fresh frame has arrived for a short hold window. The tile keeps showing its last good frame — visually nothing changes yet, but the engine has noticed.\"],\"fzo3Nc\":[\"Back to dashboard\"],\"g/QtLe\":[\"The composited canvas is encoded once per rendition and the same packets are fanned out to every output. Be honest about the current state of each transport:\"],\"g2d05t\":[\"GPU 0 compute utilisation trend\"],\"gBX5fv\":[\"Broadcast and streaming terms used across Multiview, alphabetized and searchable.\"],\"gBgZX6\":[\"STALE\"],\"gMBOF1\":[\"Loading overlays…\"],\"gOjrSt\":[\"GOP (Group of Pictures)\"],\"gZIRfg\":[\"The key idea to keep: a <0>reference</0> is trusted timing infrastructure that carries only rate and phase — it is not a video source. Facilities lock outputs to a reference and then frame-align sources to those outputs; nobody lets program content drive a device's clock, because content can stall or lie. Multiview follows the same discipline in software: its output cadence can be disciplined by a reference, but never by a source.\"],\"geodJC\":[\"Named recalls. Arm stages a salvo, Take applies it, and Cancel drops a staged one. Each command is accepted asynchronously; its outcome arrives on the realtime stream.\"],\"gtYFb8\":[\"Salvo deleted\"],\"gxl+gI\":[\"Each input continuously writes its newest decoded frame into a small per-tile store; the compositor reads the latest complete frame from that store at every output tick and never waits for an input. When a source hiccups, the store simply keeps handing out the most recent frame it has — the \\\"last good\\\" one. A brief network blip is therefore invisible: the tile holds a fraction-of-a-second-old picture until fresh frames resume.\"],\"h05sw8\":[\"Program output\"],\"h2Nmv2\":[\"In-facility broadcast distribution\"],\"hBXLF8\":[\"Decode a BT.601 stream with the BT.709 recipe (or vice versa) and every pixel is still \\\"valid\\\" — just subtly wrong: greens and reds shift, skin tones look off. Because many real-world feeds (especially IP cameras) ship with no color tags at all, Multiview detects what is signaled, fills the gaps with the same resolution-based rules real players use, converts every tile to the canvas color space before compositing, and tags the output so downstream players decode it correctly. A per-source override exists for the cases where a camera tags its stream wrongly.\"],\"hEGHqi\":[\"A named, atomically applied recall of multiview state: one salvo can switch the layout, rebind sources into cells, and update tally and labels in a single action. Borrowed from router control, where a salvo fires many crosspoint takes at once.\"],\"hVnsea\":[\"Part target (ms)\"],\"hYOxZG\":[\"What Multiview is, the design pillars, and how to get started.\"],\"hYgDIe\":[\"Create\"],\"hZGBWR\":[\"Resolved tally lamp per target.\"],\"hZO/SA\":[\"STUDIO (CAM 1)\"],\"hbPUTc\":[\"z = \",[\"0\"]],\"hfDJNk\":[\"Cancel salvo\"],\"hthlyX\":[\"2×2\"],\"hy3xCa\":[\"Recalled layout\"],\"i+yRIQ\":[\"Glass-to-glass latency\"],\"i3wc3i\":[\"This source is not part of the running engine, so it has no live state. It joins after a config export + restart binds it to a tile.\"],\"i4A317\":[\"Bring forward\"],\"i7C0Wj\":[\"Transports compared\"],\"iAav4V\":[\"This URL must start with http:// or https://.\"],\"iBNBnC\":[\"An RTSP source URL must start with rtsp:// (or rtsps://).\"],\"iCZ1lX\":[\"Tracks (comma-separated)\"],\"iDNBZe\":[\"Notifications\"],\"iFYsg9\":[\"Long-running ops\"],\"iZzdcx\":[\"Edit overlay\"],\"ibd170\":[\"Custom codec name\"],\"idD8Ev\":[\"Saved\"],\"ihjxXF\":[\"The vendor's stable handle (UUID / PCI bus id), never the index.\"],\"iq3W+B\":[\"API key\"],\"iu7tUI\":[\"Breadcrumb\"],\"iwVDYm\":[\"Transcoding\"],\"iyX/jt\":[\"Remove cell\"],\"j08k2E\":[\"Use the source wall-clock when trusted\"],\"j79j+i\":[\"<0>Last-good-frame resilience.</0> Each tile rides a live / stale / reconnecting / no-signal state machine; a failing input cannot block the compositor.\"],\"jLSLw/\":[\"Host memory: ours / used / total\"],\"jMW1qz\":[\"Picked up \",[\"0\"],\".\"],\"jN+sj6\":[\"Resilience & the tile lifecycle\"],\"jRj9RD\":[\"Live status\"],\"jT4QFP\":[\"Could not reach the control plane. Is it running?\"],\"jaJuOT\":[\"IP cameras, fixed encoders\"],\"jeIGTM\":[\"Save layout\"],\"jkoRwh\":[\"Source connections are supervised. A stalled read times out rather than hanging forever; the supervisor then reconnects with exponential backoff (so a dead camera is not hammered) and keeps trying indefinitely — sources recover without operator action whenever the far end comes back. Mid-stream surprises that normally break players, like a camera changing resolution or a stream resetting its timestamps, are absorbed inside the tile: the decoder re-initializes behind the frame store while the compositor keeps drawing the last good frame.\"],\"jmgBr4\":[\"<0>RTSP:</0> typically 0.2–1 s — a small network buffer plus the camera's encoder delay.\"],\"juGuSG\":[\"Low (~0.2–1 s)\"],\"jveFbu\":[\"Apply-layout accepted\"],\"jy3siG\":[\"CPU utilisation trend (host total)\"],\"jzykY7\":[\"An SRT URL must start with srt://.\"],\"kAXGk9\":[\"Configured ingest sources.\"],\"kAvxY7\":[\"NDI source name to advertise\"],\"kESq7H\":[\"DEC\"],\"kICD+9\":[\"Each <0>[[outputs]]</0> entry is one sink, tagged by <1>kind</1>. The canvas is composited and encoded once, then fanned out to every output. Today, file-based HLS output works; the live network output servers are on the roadmap (see the feature guide).\"],\"kLEOtI\":[\"New layout\"],\"kLEzTJ\":[\"How Multiview paces its output, what genlock and PTP mean, and how wall-clock time fits in.\"],\"kdD9FO\":[\"Low–medium (window-tuned)\"],\"knhKuu\":[\"Colour\"],\"kspIHp\":[\"Internet (TCP)\"],\"kwKdC5\":[\"RTSP (Real Time Streaming Protocol) is the standard way IP cameras and encoders publish a live stream on a local network. The client asks the device to describe and play its stream; the media itself then flows as RTP packets, either over UDP or interleaved in the same TCP connection. Latency is low (commonly a few hundred milliseconds) and the URL form is simple: <0>rtsp://camera.local:8554/main</0>.\"],\"l2OV4t\":[\"Media time\"],\"l5vYgl\":[\"SRT (Secure Reliable Transport) is an open-source UDP transport built for contribution over unmanaged networks — the public internet included. It recovers lost packets by selective retransmission inside a configurable latency window, encrypts with AES, and connects in caller, listener, or rendezvous mode so either side can initiate through firewalls.\"],\"lDgIVM\":[\"GPU access\"],\"lLd5Fv\":[\"Delete overlay\"],\"lSzRxR\":[\"Take salvo\"],\"lXja4D\":[\"The 8-bit 4:2:0 pixel layout (full-resolution brightness plane plus interleaved half-resolution color plane, 1.5 bytes per pixel) that GPUs and hardware codecs natively produce and consume. It is Multiview's working pixel format end to end — frames stay NV12 through the pipeline and color conversion happens on the GPU at tile size.\"],\"lXsRfz\":[\"CPU utilisation trend: ours over host total\"],\"lYphw3\":[\"No tally profiles are defined.\"],\"llbbQT\":[\"<0>/var/lib/multiview/hls</0> — the HLS output directory. Back it with a named volume so a sidecar (or your host) can serve the playlist and segments.\"],\"lqknUh\":[\"Pin decode to a specific GPU\"],\"m+1PpE\":[\"Paste the control-plane bearer token. Set it from the MULTIVIEW_CONTROL_TOKEN environment variable, or copy the bootstrap token the server logs once at startup. Stored in this browser only and sent as a Bearer token to the same-origin API.\"],\"m+4L4V\":[\"No live tiles yet. They appear once the engine streams a snapshot.\"],\"m16xKo\":[\"Add\"],\"m5ZXXn\":[\"Dropped onto the layout.\"],\"m7VKY4\":[\"GPU overlays\"],\"mAqNoV\":[\"<0>RTSP vs NDI in one paragraph:</0> RTSP is a pull-style protocol for reaching a specific device by address — ideal for fixed camera installs, works across routed networks, and spends very little bandwidth because the camera's compressed stream is reused as-is. NDI is a discovery-based fabric for a production LAN — sources appear by name, latency is near-frame, and quality is mezzanine-grade, but it expects a fast local network (a 1080p59.94 feed is roughly 100 Mb/s) and does not traverse the internet. Choose RTSP to monitor cameras where they are; choose NDI when the multiview sits inside a production network that already speaks it.\"],\"mCJvba\":[\"Color spaces\"],\"mJQnYa\":[\"Timing & sync\"],\"mKbM4G\":[\"The same 8-bit pixel can use two different scales. <0>Limited (\\\"TV\\\") range</0> puts black at code 16 and white at 235 — the broadcast convention virtually all video uses. <1>Full (\\\"PC\\\") range</1> uses the whole 0–255 scale — common for computer graphics, screen captures, and some webcams.\"],\"mNB9e/\":[\"Host memory used of total\"],\"mS961a\":[\"A file source plays media from disk, paced to real time so it behaves like a live feed on the wall (and can loop). Synthetic sources — color bars, solid fills, and a ticking clock — are generated in-process with no network or decode at all. They are ideal for layout work, burn-in tests, and proving the output path end to end before any real feed is connected.\"],\"mWgfWA\":[\"Snap to grid\"],\"n/2l3H\":[\"Layout or preset name (optional)\"],\"n1DfI3\":[\"Subsystem:\"],\"n3s64v\":[\"NDI\"],\"n5Z/48\":[\"Glass-to-glass latency, what each protocol adds, and the trade-offs against robustness.\"],\"nAqmn/\":[\"Kinds: <0>test</0>, <1>rtsp</1>, <2>hls</2>, <3>ts</3>, <4>srt</4>, <5>rtmp</5>, <6>ndi</6>, <7>file</7>.\"],\"nCOw5i\":[\"The stack publishes the management API and this web UI on <0>8080</0> (the mounted config carries a <1>[control]</1> listener; authenticate with the <2>MULTIVIEW_CONTROL_TOKEN</2> bearer token), the test RTSP feed on <3>8554</3> (for host inspection), and the HLS HTTP server on <4>8888</4>. HLS/LL-HLS plus RTMP and SRT push outputs run today; the live RTSP and NDI output <5>servers</5> are on the roadmap.\"],\"nE7UN+\":[\"VRAM: ours / device used / device total\"],\"nERhkx\":[\"The repeating pattern between keyframes in compressed video: a self-contained keyframe (I-frame) followed by frames that only encode differences. A viewer can only start decoding at a keyframe, so the GOP length sets a floor on channel-change and segment latency. Live encoders typically use a fixed GOP of one or two seconds.\"],\"nLQmjf\":[\"Off (pinned off)\"],\"nRo4BT\":[\"Healthcheck\"],\"nYJ4fo\":[\"Stored. It goes live via config export + restart; the running engine is unchanged until then.\"],\"nbVRlZ\":[\"The building blocks of a Multiview deployment, and what each one does.\"],\"ndATCI\":[\"Drag, resize and rotate cells on the canvas, or drop a source from the palette. The same cells are fully editable on the Cells tab without a pointer.\"],\"niSn1G\":[\"Writes an HLS playlist and segments to <0>path</0> with a <1>codec</1> and a <2>segment_ms</2> duration.\"],\"nk7Jks\":[\"Waiting for the first metrics sample…\"],\"nx4kaN\":[\"Could not save\"],\"nxS+sA\":[\"PIP\"],\"o1JPpP\":[\"Layout name\"],\"o4S09F\":[\"Rotation (°)\"],\"o5KZcH\":[\"No salvos are defined yet.\"],\"oCElWC\":[\"REST conventions\"],\"oFsG5s\":[\"Storing color information at lower resolution than brightness, exploiting the eye's lower sensitivity to color detail. Written as ratios: 4:4:4 keeps full color, 4:2:2 halves it horizontally (production quality), and 4:2:0 quarters it (virtually all delivery video). Almost every stream Multiview ingests and emits is 4:2:0.\"],\"oGKoIt\":[\"Salvo\"],\"oJ1lYJ\":[\"Internet / unmanaged links\"],\"oacR8e\":[\"API token saved\"],\"oi3ADM\":[\"Centre x (px)\"],\"opqDV9\":[\"Limited content interpreted as full: blacks turn grey, the picture looks <0>washed out and low-contrast</0>.\"],\"otpiMQ\":[\"Hardware acceleration\"],\"p/5A6m\":[\"Encoder utilisation (device total)\"],\"pJK0Gy\":[\"Teletext page\"],\"pSORut\":[\"Resolved tally lamps, a manual override, and the tally profiles that map incoming protocol words to lamps.\"],\"pXOFB7\":[\"No alarms match the current filter.\"],\"pYwpTF\":[\"Enter a full URL with a host. Wrap an IPv6 literal in brackets, e.g. rtsp://[2001:db8::1]:8554/cam.\"],\"pexTfY\":[\"Multicast\"],\"pfa8F0\":[\"Display name\"],\"pgrQUb\":[\"Recovery has not succeeded within the no-signal timeout. The tile switches to a clear \\\"signal lost\\\" slate — an honest statement that what is on screen is no longer recent video.\"],\"pjJ4wm\":[\"docker run and docker compose, GPU access, volumes, healthchecks, and the API token.\"],\"q2wpvM\":[\"The output clock\"],\"q4NVvb\":[\"Timezone offset (minutes from UTC)\"],\"q9EP8O\":[\"Arm\"],\"qDhn7R\":[\"CUDA-enabled image (NVDEC / NVENC plus a wgpu compositor) for NVIDIA GPUs.\"],\"qG9wMb\":[\"Save & apply to engine\"],\"qGj9cx\":[\"<0>RTMP:</0> a few seconds of TCP and player buffering.\"],\"qNmdL6\":[\"Changing an output's codec is a controlled restart of that output (consumers reconnect); it never interrupts the compositor or the other outputs. The codec field on an output is validated against what the transport can carry — for example <0>h265</0> is rejected on classic RTMP — and against what the host can actually encode.\"],\"qXeD+k\":[\"Could not load outputs:\"],\"qZEXiU\":[\"Edit salvo\"],\"qbeyiU\":[\"Export not available\"],\"qf53BF\":[\"A TCP push protocol that remains the most widely accepted way to send a live stream to a platform. Classic RTMP carries H.264 and AAC only; enhanced endpoints negotiate newer codecs. Latency is typically a few seconds.\"],\"qpBd9Z\":[\"HDR (high dynamic range) streams use a different brightness curve — PQ or HLG instead of the SDR gamma — and usually the BT.2020 gamut, letting them represent far brighter highlights and deeper shadow detail. An HDR tile dropped onto an SDR canvas without conversion looks dim and grey (its values are being read with the wrong curve), and an SDR tile pushed through an HDR curve blows out.\"],\"qpW/VF\":[\"NO SIGNAL\"],\"qsFKJP\":[\"Accessible editing path: planned (Cells form + Inspector)\"],\"qx+J9F\":[\"Mount a config file and an output directory, then point the binary at the config. The current binary composites, encodes, and writes HLS or file output to disk.\"],\"r3T2Tg\":[\"Loading tally state…\"],\"r3y/cA\":[\"MPEG-TS over UDP and multicast\"],\"r6y+jM\":[\"Warning\"],\"rHmYNB\":[\"Border colour\"],\"rJj3af\":[\"Glass-to-glass latency is the time from light hitting a camera sensor (\\\"first glass\\\") to the picture appearing on a display (\\\"second glass\\\"). It is a chain of small budgets, and every hop adds some: the camera's own encoder, the network transport, any receive/jitter buffering, decoding, compositing, re-encoding the canvas, the output transport, and finally the viewer's player buffer. No single component \\\"is\\\" the latency — the chain is.\"],\"rdU729\":[\"Layout\"],\"rgBYIK\":[\"Monitoring cameras where they are installed: RTSP.\"],\"rguawE\":[\"Fix the highlighted fields, then save again.\"],\"rp0Bd0\":[\"Compute\"],\"rsrlyy\":[\"A small RTSP server that, on start, runs ffmpeg to publish a synthetic test pattern with a sine-wave audio tone to <0>rtsp://testsrc:8554/test</0>.\"],\"rxWGWX\":[\"Forward\"],\"s/b3qO\":[\"Transcoding is decoding compressed video back to raw pictures and recompressing it — usually into a different codec, size, or bitrate. Every transcode costs three things: <0>quality</0> (each recompression is a new lossy generation), <1>latency</1> (decoding and re-encoding both buffer frames), and <2>compute</2> (encoding is by far the most expensive step in a video pipeline). Good systems therefore transcode only when they must, and exactly once.\"],\"s/ze0K\":[\"This is also why one bad source can never take down the wall: the disturbance is contained to that tile's rectangle. The output keeps emitting a complete, valid frame every tick regardless — even if every source died at once, the canvas would show slates and a still-ticking clock, not stop.\"],\"s1vLVC\":[\"When the config has a <0>[control]</0> section, the binary binds that listener and serves the web UI, REST API, and docs alongside the engine. Authenticate callers with a bearer token — supply it through the <1>MULTIVIEW_CONTROL_TOKEN</1> environment variable so it is never baked into an image or written to the config file. The presented token is <2>admin.<secret></2>; if the variable is unset, the server generates one and logs it once at startup. Publish the listener's port (default <3>8080</3>) to reach it.\"],\"s3knYL\":[\"NV12\"],\"s45mWi\":[\"Drag cancelled.\"],\"sBJ5MF\":[\"المصادر\"],\"sDXD1A\":[\"Layout deleted\"],\"sJGljQ\":[\"Identifier\"],\"sMcvHF\":[\"The REST base, long-running operations, ETags, the WebSocket and SSE streams, and the live API playground.\"],\"sOdcj7\":[\"Configuration exported\"],\"sUkgF5\":[\"About codecs and transcoding\"],\"sVSPnh\":[\"Changes saved here are stored, not yet live: the engine does not hot-add sources or outputs. Apply them by exporting the configuration and restarting Multiview. Layout apply, source swap, routing, and salvos act on the running engine immediately.\"],\"sX2In9\":[\"Live engine status at a glance.\"],\"seGwMJ\":[\"Limited vs full range\"],\"sf5PzT\":[\"Exact \\\"num/den\\\", e.g. 30/1 or 30000/1001 — never a float.\"],\"sjpNlF\":[\"Acknowledge alarm\"],\"spG2Ba\":[\"Every tile rides its own four-state ladder, independently of every other tile. The state is shown as a badge in the UI and decides what the tile draws:\"],\"srTca3\":[\"<0>Continuous output.</0> One monotonic output clock produces a valid, correctly-timestamped frame every tick, independent of any input.\"],\"sxkWRg\":[\"Advanced\"],\"t/YqKh\":[\"Remove\"],\"t9SOnh\":[\"Overlays draw on top of the canvas or a single tile: clocks, text labels and under-monitor displays, and tally borders. A clock overlay sourced from the wall clock keeps ticking every frame, which doubles as a visible sentinel that the output is still alive.\"],\"tBXgbc\":[\"This permanently removes the salvo definition.\"],\"tJUHio\":[\"<0>SRT:</0> the configured latency window (commonly 120 ms to a few seconds) — you are explicitly buying loss recovery with delay.\"],\"tLkESF\":[\"open documentation\"],\"tfDRzk\":[\"Save\"],\"tuDIq6\":[\"No cells yet. Add one to start composing the multiview.\"],\"tycwDS\":[\"What each protocol adds to latency\"],\"u2fWGl\":[\"Unacknowledged\"],\"u4iXQi\":[\"Fit\"],\"u7BWzS\":[\"Fully deterministic\"],\"uAQUqI\":[\"Status\"],\"uF87uU\":[\"<0>Wall clock</0> — says <1>what time of day</1> it is (for clocks and stream metadata).\"],\"uISnsY\":[\"Could not delete\"],\"uJF096\":[\"Change log, newest first.\"],\"uR+F2A\":[\"HLS / LL-HLS\"],\"uSzU3k\":[\"Compose the output multiview. The Canvas tab is drag-and-drop; the Cells tab is the fully keyboard-operable equivalent.\"],\"uVbqRY\":[\"Multiview's output is paced by exactly one thing: a fixed-cadence internal clock. At every tick — for example every 1/50 s for a 50 fps canvas — it emits one finished frame, forever. Sources never set that pace. Each input writes its newest decoded frame into a per-tile store, and at each tick the compositor <0>samples</0> whatever is freshest there. A source that bursts, stalls, or dies changes only what its own tile shows — never when the next output frame goes out.\"],\"udUo7G\":[\"The LIVE / STALE / RECONNECTING / NO SIGNAL ladder, last-good frames, and why output never stalls.\"],\"ulCpXj\":[\"About color spaces and range\"],\"ululiN\":[\"No recovery; loss = glitch\"],\"upn7BW\":[\"Filter by object id\"],\"uprOiC\":[\"Amber\"],\"uvea3H\":[\"Output cadence as a <0>\\\"num/den\\\"</0> rational string, for example <1>\\\"30000/1001\\\"</1> for exact NTSC 29.97. A bare float is rejected on purpose, because frame rates must be exact.\"],\"v+Co07\":[\"<0>/etc/multiview/multiview.toml</0> — the config file, mounted read-only.\"],\"v8o+Rn\":[\"Memory\"],\"vGjmyl\":[\"Deleted\"],\"vJy1BK\":[\"This permanently removes the stored resource. The running engine is not affected until a new configuration is applied.\"],\"vMyDgh\":[\"A name is required.\"],\"vPemUP\":[\"Matrix\"],\"vSAN9+\":[\"NVIDIA\"],\"vSCYDx\":[\"Wall-clock handling\"],\"vV3G4D\":[\"Open the API playground\"],\"vWUa8t\":[\"That key was not accepted. Check it and try again.\"],\"vXIe7J\":[\"Language\"],\"vYHVvJ\":[\"Buffers and lags under loss\"],\"vabBy5\":[\"Secure Reliable Transport — an open-source UDP protocol for carrying streams across unmanaged networks. It repairs packet loss by retransmission inside a configurable latency window and encrypts with AES, making it the standard choice for contribution over the internet.\"],\"vgGyjB\":[\"A tiny nginx that serves the HLS volume over HTTP so you can open the stream in a player at <0>http://localhost:8888/multiview.m3u8</0>.\"],\"vrQQgz\":[\"Profiles\"],\"vvCT/r\":[\"Where to go next\"],\"vvd1b1\":[\"Timezone offset (minutes from UTC, optional)\"],\"vws1ZU\":[\"Decoder utilisation (device total)\"],\"vxEE+J\":[\"Run Multiview with Docker — single container or the compose stack — with optional GPU access, persistent volumes, and healthchecks.\"],\"w0C2AZ\":[\"Brightness\"],\"w8+sul\":[\"Intel / AMD (VAAPI)\"],\"w8qaBX\":[\"How Multiview relates: the fixed-cadence output clock free-runs on the host's monotonic clock by default — no timing hardware needed. In a PTP facility the same clock can be <0>disciplined</0> to the grandmaster (its rate gently steered, never stepped), and if the reference disappears the output coasts and then free-runs — it never stops. Inputs remain sampled, never pacing, in every mode; PTP changes how well sources line up with each other, not who controls the output.\"],\"w9ii4v\":[\"About overlays\"],\"wBOpo7\":[\"AV1\"],\"wHRlTn\":[\"Arm salvo\"],\"wJ7fXL\":[\"NDI source name\"],\"wLajWD\":[\"Clear override\"],\"wPPdjY\":[\"How RTSP, NDI, SRT, RTMP, HLS, MPEG-TS, and file sources carry video — and which one fits which job.\"],\"wRTiSD\":[\"Red\"],\"wXIIT7\":[\"Caption field / service\"],\"wYzAhK\":[\"Sidecar file path\"],\"wbOpwP\":[\"Tiles\"],\"wdxz7K\":[\"Source\"],\"whTwoN\":[\"New output\"],\"wpa76y\":[\"Salvo created\"],\"x11zyz\":[\"Latency profile (optional)\"],\"x5hwBQ\":[\"Files and synthetic sources\"],\"x8Sui5\":[\"High (6–30 s) / medium (2–5 s)\"],\"xBSaWD\":[\"Fill colour\"],\"xCJdfg\":[\"Clear\"],\"xDr4s8\":[\"How Multiview works, how to run it, and how to drive it from config-as-code or the API.\"],\"xEh/gj\":[\"This is one of the most common picture-quality bugs in any video chain. Multiview expands each tile's range exactly once on ingest, composites in a common working space, and compresses exactly once on output — and tags the result, because an untagged-but-correct stream still gets guessed wrong by some players.\"],\"xMpK5S\":[\"Loading profiles…\"],\"xOOA5k\":[\"Video using a brightness curve (PQ or HLG) and usually the BT.2020 gamut that represents far brighter highlights and deeper shadows than standard dynamic range (SDR). HDR tiles must be tone-mapped onto an SDR canvas or they look dim and grey.\"],\"xZ9mgm\":[\"These are classes, not promises — encoder settings (especially keyframe interval), network conditions, and the viewer's player all move the number.\"],\"xcsD/d\":[\"Force lamp\"],\"xjfMml\":[\"None needed\"],\"xl6GWt\":[\"Accessible editing path: Cells form + Inspector in the editor\"],\"xw4nV6\":[\"Delete layout?\"],\"xysWtw\":[\"Active only\"],\"xziKPE\":[\"Glossary\"],\"y+qYa2\":[\"An honest comparison — figures are typical classes, not guarantees; the network you run on dominates:\"],\"y2gK6o\":[\"Pass through the host render node and add the container user to the group that owns it. The render group id varies by host — look it up with <0>getent group render</0>.\"],\"y8CmDD\":[\"Frame rate (rational)\"],\"yC+8P8\":[\"Typical use\"],\"yGiixQ\":[\"Tally profiles and their rule counts.\"],\"yKBF3l\":[\"API access\"],\"yKLhbY\":[\"Could not load tally state:\"],\"yPZUKa\":[\"Dropped outside any target; nothing changed.\"],\"yU0QVO\":[\"التخطيطات\"],\"yWNAen\":[\"Send backward\"],\"yb5jR0\":[\"The cell extends outside the canvas.\"],\"yhdLak\":[\"Delete layout\"],\"yoI+AL\":[\"A video stream does not just carry pixel values — it carries an agreement about what those values <0>mean</0>. Three standards cover almost everything: <1>BT.601</1> (standard definition), <2>BT.709</2> (high definition — the default assumption for most content today), and <3>BT.2020</3> (ultra-HD and HDR, with a much wider color gamut). Each defines its own recipe for turning the YUV numbers in the stream back into red, green, and blue.\"],\"yotN7L\":[\"Could not load the audit log:\"],\"yqumrh\":[\"Show a test notification\"],\"yums+g\":[\"Layout saved, but apply failed\"],\"yuwf/m\":[\"Each cell carries its own normalized rectangle (0.0–1.0) in a <0>rect</0> field.\"],\"yvgPi+\":[\"Inputs\"],\"z036HG\":[\"Latency, robustness, and scale pull against each other. Buffering is what absorbs network jitter and gives retransmission time to repair loss — so cutting the buffer cuts your protection with it. A 120 ms SRT window is snappy but fragile on a lossy link; a 2 s window rides out trouble at the cost of 2 s. Plain HTTP segments are the most robust and scalable delivery there is, and also the slowest.\"],\"z4TzmD\":[\"About tile lifecycle states\"],\"z5F1i6\":[\"Inside a production network that already speaks it: NDI.\"],\"zPGNJm\":[\"Transfer\"],\"zR7u/o\":[\"This control plane does not serve config export yet. Update the server to use it.\"],\"zSybou\":[\"Timezone offset (minutes)\"],\"zVaheC\":[\"What Multiview is\"],\"zcTbIb\":[\"Transport comparison: latency class, network fit, robustness, and typical use.\"],\"zfCOpB\":[\"Configured multiview layouts.\"],\"zmN9ps\":[\"Alarms are raised by content-aware fault probes attached to a tile. Probes can detect a black picture, a frozen picture, audio silence, and loudness that drifts from an EBU R128 target. Each probe has a severity and dwell timers, so a brief glitch does not trip an alarm while a sustained fault does. Severities follow the standard cleared / indeterminate / warning / minor / major / critical scale.\"],\"zo6NEX\":[\"New overlay\"],\"zq2Cor\":[\"Height (px)\"],\"zufG7m\":[\"MPEG-TS (Transport Stream)\"],\"zwrQMA\":[\"Segment (ms)\"]}")as Messages;